Rule.Source:

import sailpoint.object.Identity;
import sailpoint.tools.Util; 

  log.debug("Entering Rule : ASCN-Rule-GroupAggregationRefresh-GCP");
  log.info("Group Aggregation refresh rule for GSuite app to mark additional GCP groups as requestable based on individual entitlement approval configuration");
  if (accountGroup != null ) { 
      Identity owner = accountGroup.getOwner();
      String additionalApproverString = accountGroup.getAttribute("additionalApprover");      
      Identity additionalApprover = context.getObjectByName(Identity.class, additionalApproverString);
      boolean approvalTypeMatch = Util.nullSafeCaseInsensitiveEq(accountGroup.getAttribute("approvalType"), "manager,owner,identity");
              
      if (owner != null && owner.isWorkgroup() && approvalTypeMatch && Util.isNotNullOrEmpty(additionalApproverString) && additionalApprover != null && additionalApprover.isWorkgroup()) {         
          accountGroup.setRequestable(true);
          return accountGroup;
      } else {
          accountGroup.setRequestable(false);
      }
  log.debug("Exiting Rule : ASCN-Rule-GroupAggregationRefresh-GCP");
  return accountGroup;
  }
